using Avalonia;
using Avalonia.Controls;

namespace VisualRelay.App.Views.Controls.Buttons;

/// <summary>
/// The standard visual appearance of a <see cref="CommonButton"/>,
/// corresponding to the theme style classes defined in
/// <c>VisualRelayTheme.axaml</c>.
/// </summary>
public enum ButtonAppearance
{
    /// <summary>Blue primary-action button (theme class "primary").</summary>
    Primary = 0,

    /// <summary>Grey default button (no extra style class).</summary>
    Default,

    /// <summary>Yellow warning/pause button (theme class "warning").</summary>
    Warning,

    /// <summary>Transparent blue link (theme class "hyperlink").</summary>
    Hyperlink,

    /// <summary>Dark folder-path button (theme class "path").</summary>
    Path,
}

/// <summary>
/// Every general-purpose text button in the app.  Set
/// <see cref="Appearance"/> to choose the visual variant; the control
/// automatically applies the matching Avalonia style class so the
/// existing theme selectors (<c>Button.primary</c>, <c>Button.warning</c>,
/// etc.) match without any theme changes.
///
/// When <see cref="Glyph"/> is set the control prepends a small
/// <see cref="TextBlock"/> before the <see cref="ContentControl.Content"/>,
/// replacing the old inline-⚙ pattern.
/// </summary>
public partial class CommonButton : Button
{
    // Ensure the Button theme (template, visual states, pointer handling)
    // from the Fluent theme applies exactly as it does to plain Button.
    protected override Type StyleKeyOverride => typeof(Button);
    /// <summary>
    /// Identifies the <see cref="Appearance"/> styled property.
    /// </summary>
    public static readonly StyledProperty<ButtonAppearance> AppearanceProperty =
        AvaloniaProperty.Register<CommonButton, ButtonAppearance>(
            nameof(Appearance),
            defaultValue: ButtonAppearance.Default);

    /// <summary>
    /// Identifies the <see cref="Glyph"/> styled property.
    /// </summary>
    public static readonly StyledProperty<string?> GlyphProperty =
        AvaloniaProperty.Register<CommonButton, string?>(
            nameof(Glyph));

    /// <summary>The original <see cref="ContentControl.Content"/> set by the
    /// consumer, saved so we can re-wrap it when <see cref="Glyph"/> changes.</summary>
    private object? _originalContent;

    /// <summary>Whether we are currently wrapping content for a glyph.</summary>
    private bool _isWrapping;

    static CommonButton()
    {
        AppearanceProperty.Changed.AddClassHandler<CommonButton>(OnAppearanceChanged);
        GlyphProperty.Changed.AddClassHandler<CommonButton>(OnGlyphChanged);
    }

    public CommonButton()
    {
    }

    /// <summary>The visual variant of this button.</summary>
    public ButtonAppearance Appearance
    {
        get => GetValue(AppearanceProperty);
        set => SetValue(AppearanceProperty, value);
    }

    /// <summary>
    /// Optional Unicode glyph (e.g. "⚙") to prepend before the button
    /// <see cref="ContentControl.Content"/>.  When set the control
    /// automatically wraps content in a horizontal <see cref="StackPanel"/>.
    /// </summary>
    public string? Glyph
    {
        get => GetValue(GlyphProperty);
        set => SetValue(GlyphProperty, value);
    }

    /// <inheritdoc />
    protected override void OnPropertyChanged(AvaloniaPropertyChangedEventArgs change)
    {
        base.OnPropertyChanged(change);

        // Capture the raw content before Glyph logic wraps it.
        if (change.Property == ContentProperty && !_isWrapping)
        {
            _originalContent = change.NewValue;
            ApplyGlyph();
        }
    }

    private static void OnAppearanceChanged(CommonButton button, AvaloniaPropertyChangedEventArgs e)
    {
        button.ApplyAppearance((ButtonAppearance)(e.NewValue ?? ButtonAppearance.Default));
    }

    private static void OnGlyphChanged(CommonButton button, AvaloniaPropertyChangedEventArgs e)
    {
        button.ApplyGlyph();
    }

    private void ApplyAppearance(ButtonAppearance appearance)
    {
        Classes.Remove("primary");
        Classes.Remove("warning");
        Classes.Remove("hyperlink");
        Classes.Remove("path");

        switch (appearance)
        {
            case ButtonAppearance.Primary:
                Classes.Add("primary");
                break;
            case ButtonAppearance.Warning:
                Classes.Add("warning");
                break;
            case ButtonAppearance.Hyperlink:
                Classes.Add("hyperlink");
                break;
            case ButtonAppearance.Path:
                Classes.Add("path");
                break;
        }
    }

    private void ApplyGlyph()
    {
        _isWrapping = true;
        try
        {
            var glyph = Glyph;
            var content = _originalContent;

            if (string.IsNullOrEmpty(glyph) || content is null)
            {
                Content = content;
                return;
            }

            Content = new StackPanel
            {
                Orientation = Avalonia.Layout.Orientation.Horizontal,
                Spacing = 6,
                Children =
                {
                    new TextBlock
                    {
                        Text = glyph,
                        FontSize = 14,
                        VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    },
                    CreateContentPresenter(content),
                },
            };
        }
        finally
        {
            _isWrapping = false;
        }
    }

    /// <summary>
    /// Wraps a string content value in a <see cref="TextBlock"/> so it
    /// renders; passes through any other object unchanged (it will be
    /// hosted by Avalonia's content presenter inside the StackPanel).
    /// </summary>
    private static Control CreateContentPresenter(object content)
    {
        if (content is string s)
        {
            return new TextBlock
            {
                Text = s,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };
        }

        // For non-string content (e.g. a Grid), wrap in a ContentControl
        // so it renders inside the StackPanel.
        return new ContentControl
        {
            Content = content,
            VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
        };
    }
}

using Avalonia;
using Avalonia.Controls;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.App.Views.Controls.Buttons;

/// <summary>
/// The icon style for an <see cref="IconButton"/>.
/// </summary>
public enum IconButtonStyle
{
    /// <summary>26×26 collapse/expand chevron toggle (theme class "collapseToggle").</summary>
    CollapseToggle,

    /// <summary>34×30 focus/restore toggle (theme class "focusToggle").</summary>
    FocusToggle,
}

/// <summary>
/// An icon-only toggle button that auto-composes the correct vector icon
/// (<see cref="Controls.ChevronIcon"/> or <see cref="Controls.FocusToggleIcon"/>)
/// and applies the matching Avalonia style class so the existing theme
/// selectors (<c>Button.collapseToggle</c>, <c>Button.focusToggle</c>)
/// match without any theme changes.
///
/// Bind <see cref="ChevronDirection"/> when <see cref="IconStyle"/> is
/// <see cref="IconButtonStyle.CollapseToggle"/>, and
/// <see cref="IsContracted"/> when <see cref="IconStyle"/> is
/// <see cref="IconButtonStyle.FocusToggle"/>.
/// </summary>
public partial class IconButton : Button
{
    protected override Type StyleKeyOverride => typeof(Button);
    /// <summary>
    /// Identifies the <see cref="IconStyle"/> styled property.
    /// </summary>
    public static readonly StyledProperty<IconButtonStyle> IconStyleProperty =
        AvaloniaProperty.Register<IconButton, IconButtonStyle>(
            nameof(IconStyle));

    /// <summary>
    /// Identifies the <see cref="ChevronDirection"/> styled property.
    /// Only relevant when <see cref="IconStyle"/> is
    /// <see cref="IconButtonStyle.CollapseToggle"/>.
    /// </summary>
    public static readonly StyledProperty<ChevronDirection> ChevronDirectionProperty =
        AvaloniaProperty.Register<IconButton, ChevronDirection>(
            nameof(ChevronDirection),
            defaultValue: ChevronDirection.Right);

    /// <summary>
    /// Identifies the <see cref="IsContracted"/> styled property.
    /// Only relevant when <see cref="IconStyle"/> is
    /// <see cref="IconButtonStyle.FocusToggle"/>.
    /// </summary>
    public static readonly StyledProperty<bool> IsContractedProperty =
        AvaloniaProperty.Register<IconButton, bool>(
            nameof(IsContracted));

    static IconButton()
    {
        IconStyleProperty.Changed.AddClassHandler<IconButton>(OnIconStyleChanged);
    }

    public IconButton()
    {
        ApplyIconStyle(IconStyle);
    }

    /// <summary>Which icon this button displays.</summary>
    public IconButtonStyle IconStyle
    {
        get => GetValue(IconStyleProperty);
        set => SetValue(IconStyleProperty, value);
    }

    /// <summary>
    /// Direction of the collapse/expand chevron.
    /// Only relevant when <see cref="IconStyle"/> is
    /// <see cref="IconButtonStyle.CollapseToggle"/>.
    /// </summary>
    public ChevronDirection ChevronDirection
    {
        get => GetValue(ChevronDirectionProperty);
        set => SetValue(ChevronDirectionProperty, value);
    }

    /// <summary>
    /// Whether the focus toggle is in the contracted (restore) state.
    /// Only relevant when <see cref="IconStyle"/> is
    /// <see cref="IconButtonStyle.FocusToggle"/>.
    /// </summary>
    public bool IsContracted
    {
        get => GetValue(IsContractedProperty);
        set => SetValue(IsContractedProperty, value);
    }

    private static void OnIconStyleChanged(IconButton button, AvaloniaPropertyChangedEventArgs e)
    {
        button.ApplyIconStyle((IconButtonStyle)(e.NewValue ?? IconButtonStyle.CollapseToggle));
    }

    private void ApplyIconStyle(IconButtonStyle style)
    {
        Classes.Remove("collapseToggle");
        Classes.Remove("focusToggle");

        switch (style)
        {
            case IconButtonStyle.CollapseToggle:
                Classes.Add("collapseToggle");
                var chevron = new ChevronIcon();
                chevron.Bind(ChevronIcon.DirectionProperty,
                    this.GetObservable(ChevronDirectionProperty));
                Content = chevron;
                break;
            case IconButtonStyle.FocusToggle:
                Classes.Add("focusToggle");
                var focusIcon = new FocusToggleIcon();
                focusIcon.Bind(FocusToggleIcon.IsContractedProperty,
                    this.GetObservable(IsContractedProperty));
                Content = focusIcon;
                break;
        }
    }
}

using Avalonia.Controls;

namespace VisualRelay.App.Views.Controls.Buttons;

/// <summary>
/// A stage card in the stage board.  Automatically applies the
/// <c>"stageButton"</c> style class so the theme selectors
/// (<c>Button.stageButton</c>) match without theme changes.
/// Rich child content is provided via the existing
/// <see cref="DataTemplate"/> in <c>StageBoard.axaml</c>.
/// </summary>
public partial class StageCardButton : Button
{
    protected override Type StyleKeyOverride => typeof(Button);
    public StageCardButton()
    {
        Classes.Add("stageButton");
    }
}

