/// <summary>
/// No class may inherit directly from <c>Button</c>.  Custom button
/// components must use composition (wrapping a <c>Button</c> inside a
/// <c>ContentControl</c> or similar) rather than inheritance, so that
/// callers cannot override arbitrary Button properties inline and create
/// inconsistent button appearances.
/// </summary>
[Fact]
public void NoClassInheritsFromButton()
{
    var violations = new List<string>();
    var appsrcDir = Path.Combine(RepoRoot, "src", "VisualRelay.App");
    if (!Directory.Exists(appsrcDir))
    {
        Assert.Fail($"Source directory does not exist: {appsrcDir}");
        return;
    }

    var files = Directory.GetFiles(appsrcDir, "*.cs", SearchOption.AllDirectories)
        .OrderBy(f => f)
        .ToList();

    Assert.True(files.Count > 0,
        $"No .cs files found under {appsrcDir}. "
        + "The source directory must exist and contain C# files.");

    foreach (var file in files)
    {
        var matches = FindButtonInheritance(file);
        if (matches.Count > 0)
        {
            var relativePath = Path.GetRelativePath(RepoRoot, file);
            foreach (var (line, text) in matches)
                violations.Add($"  {relativePath}:{line}  →  {text}");
        }
    }

    Assert.True(violations.Count == 0,
        $"Found {violations.Count} class(es) inheriting from Button.  "
        + "Custom button components must use composition over inheritance.  "
        + "Wrap a Button inside a ContentControl (or similar) instead of "
        + "extending Button directly.\n\n"
        + $"Violations:\n{string.Join("\n", violations)}");
}

